-- PawHub v2.0.0
do
local function xor(a,b)
 local r=0;local t=1
 while a>0 or b>0 do
  if(a%2)~=(b%2)then r=r+t end
  a=math.floor(a/2);b=math.floor(b/2);t=t*2
 end
 return r
end
local function b64(s)
 local r='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
 local c={};local f=math.floor
 for i=1,#s,4 do
  local p={}
  for j=0,3 do
   local ch=s:sub(i+j,i+j)
   for k=1,#r do if r[k]==ch then p[j+1]=k-1 break end end
   if ch=='='then p[j+1]=nil end
  end
  local v=(p[1]or 0)*262144+(p[2]or 0)*4096+(p[3]or 0)*64+(p[4]or 0)
  c[#c+1]=string.char(f(v/65536))
  if p[3]then c[#c+1]=string.char(f((v%65536)/256))end
  if p[4]then c[#c+1]=string.char(f(v%256))end
 end
 return table.concat(c)
end
local function xdata(d,k)
 local r={}
 for i=1,#d do
  r[i]=string.char(xor(string.byte(d,i),string.byte(k,((i-1)%#k)+1)))
 end
 return table.concat(r)
end
local function getkey()
 local a={112,64,119,104,85,98,95,50,48,50,52,95,120,79,114,95,51,110,99,82,121,112,116,95,86,50,95,83,84,64,82}
 local s=''
 for i=1,#a do s=s..string.char(a[i])end
 return s
end
local p=game:GetService('Players')
local h=game:GetService('HttpService')
if p.LocalPlayer and h then
 local e=[[            ]]
 local a=b64(e)
 local b=xdata(a,getkey())
 if b:byte(1)==239 then b=b:sub(4)end
 local fn,err=loadstring(b)
 if fn then pcall(fn)else warn('[PawHub] Error: '..err)end
end
end